One issue with flood fill is that it relies on the full array being instantiated. Again, this is no worse than the current approach, but in the long term, we probably want to fill across lazy array chunks — fill in the current chunk, and only load adjacent chunks if we hit the edges. Alternatively, we could use region growing — load increasingly larger regions as we flood, without bothering to align with chunks — the alignment might not matter too much if we use caching.","reactions":{"url":"https://api.github.com/repos/napari/napari/issues/2379/reactions","total_count":1,"+1":1,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"timeline_url":"https://api.github.com/repos/napari/napari/issues/2379/timeline","performed_via_github_app":null,"state_reason":null},"comment":{"url":"https://api.github.com/repos/napari/napari/issues/comments/2550608868","html_url":"https://github.com/napari/napari/issues/2379#issuecomment-2550608868","issue_url":"https://api.github.com/repos/napari/napari/issues/2379","id":2550608868,"node_id":"IC_kwDOCJ0aI86YBzPk","user":{"login":"jni","id":492549,"node_id":"MDQ6VXNlcjQ5MjU0OQ==","avatar_url":"https://avatars.githubusercontent.com/u/492549?v=4","gravatar_id":"","url":"https://api.github.com/users/jni","html_url":"https://github.com/jni","followers_url":"https://api.github.com/users/jni/followers","following_url":"https://api.github.com/users/jni/following{/other_user}","gists_url":"https://api.github.com/users/jni/gists{/gist_id}","starred_url":"https://api.github.com/users/jni/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/jni/subscriptions","organizations_url":"https://api.github.com/users/jni/orgs","repos_url":"https://api.github.com/users/jni/repos","events_url":"https://api.github.com/users/jni/events{/privacy}","received_events_url":"https://api.github.com/users/jni/received_events","type":"User","user_view_type":"public","site_admin":false},"created_at":"2024-12-18T07:59:54Z","update